let b = $json.body ?? $json ?? {};
if (typeof b === 'string') {
  try { b = JSON.parse(b); } catch { b = { raw_body: b }; }
}
const clean = (value, max = 500) => String(value || '').replace(/[\r\n\t]+/g, ' ').trim().slice(0, max);
const eventType = clean(b.event_type || 'page_view', 80);
const timestamp = b.timestamp && !Number.isNaN(Date.parse(b.timestamp)) ? new Date(b.timestamp) : new Date();
const referrer = clean(b.referrer, 800);
const utmSource = clean(b.utm_source, 120).toLowerCase();
const sourceText = [utmSource, referrer, clean(b.fbclid, 250)].join(' ').toLowerCase();
const isMetaTraffic = Boolean(sourceText.match(/facebook|instagram|meta|fbclid|l\.facebook|lm\.facebook|m\.facebook|l\.instagram/));
const record = {
  timestamp: timestamp.toISOString(),
  event_date: timestamp.toISOString().slice(0, 10),
  event_hour: timestamp.toISOString().slice(0, 13),
  event_type: eventType,
  site: clean(b.site || 'thegtcollective.com', 120),
  page_url: clean(b.page_url || b.landing_url || b.source_url, 1000),
  path: clean(b.path || '/', 250),
  page_title: clean(b.page_title, 250),
  referrer,
  landing_url: clean(b.landing_url, 1000),
  utm_source: clean(b.utm_source, 120),
  utm_medium: clean(b.utm_medium, 120),
  utm_campaign: clean(b.utm_campaign, 180),
  utm_content: clean(b.utm_content, 180),
  utm_term: clean(b.utm_term, 180),
  fbclid: clean(b.fbclid, 250),
  gclid: clean(b.gclid, 250),
  visitor_id: clean(b.visitor_id, 120),
  session_id: clean(b.session_id, 120),
  language: clean(b.language, 80),
  timezone: clean(b.timezone, 80),
  screen: clean(b.screen, 80),
  user_agent: clean(b.user_agent, 500),
  is_meta_traffic: isMetaTraffic
};
return [{
  json: { ok: true, record },
  binary: {
    data: {
      data: Buffer.from(JSON.stringify(record) + '\n', 'utf8').toString('base64'),
      mimeType: 'application/jsonl',
      fileName: 'gt-website-traffic.jsonl'
    }
  }
}];
